import React, { useState } from 'react';
import Course from './Course';
import InstructorPage from './InstructorPage';

const App = () => {
  const [currentPage, setCurrentPage] = useState('courses');

  return (
    <div>
      {/* Navigation */}
      <nav className="bg-white shadow-sm border-b fixed w-full z-50">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex justify-between items-center h-16">
            <div className="flex space-x-8">
              <button 
                onClick={() => setCurrentPage('courses')}
                className={`px-3 py-2 text-sm font-medium ${
                  currentPage === 'courses' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-600'
                }`}
              >
                Courses
              </button>
              <button 
                onClick={() => setCurrentPage('instructor')}
                className={`px-3 py-2 text-sm font-medium ${
                  currentPage === 'instructor' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-600'
                }`}
              >
                Instructor Dashboard
              </button>
            </div>
          </div>
        </div>
      </nav>

      {/* Page Content */}
      <div className="pt-16">
        {currentPage === 'courses' && <Course />}
        {currentPage === 'instructor' && <InstructorPage />}
      </div>
    </div>
  );
};

export default App;
